class Solution {
    public int lengthAfterTransformations(String s, int t, List<Integer> nums) {
        int MOD = (int) 1e9 + 7;
        long[] dp = new long[26];
        for (int i = 0; i < 26; i++) {
            dp[i] = nums.get(i);
        }
        for (int i = 0; i < t; i++) {
            long[] next = new long[26];
            for (int j = 0; j < 26; j++) {
                next[j] = (dp[j] + dp[(int) ((j + nums.get(j)) % 26)] - 1) % MOD;
            }
            dp = next;
        }
        long ans = 0;
        for (char c : s.toCharArray()) {
            ans = (ans + dp[c - 'a']) % MOD;
        }
        return (int) ans;
    }
}
